const imageUrl = useDeviceValue({
  mobile: '/path/to/mobile.png',
  tablet: '/path/to/tablet.png',
  desktop: '/path/to/desktop.png'
});

<img src={imageUrl} alt="Responsive image" />

const ref = useRef<HTMLDivElement>(null);
const { hasFocus } = useFocus(ref.current);

<div ref={ref} style={{ outline: hasFocus ? '2px solid blue' : 'none' }}>
  Hover or focus me
</div>

const contentRef = useRef<HTMLDivElement>(null);
const contentHeight = useHeightCalculator(contentRef);

<div style={{ height: isOpen ? contentHeight : 0, overflow: 'hidden', transition: 'height 0.3s' }}>
  <div ref={contentRef}>Collapsible content</div>
</div>

useMount(() => {
  fetchInitialData();
  return () => cleanup();
});

const breakpoint = useWindowBreakpoint();
const isMobile = breakpoint <= BREAKPOINTS.sm;

<div>{isMobile ? 'Mobile layout' : 'Desktop layout'}</div>

